  ('fire-eq-tech-moex-00835', 'fire-eq-tech', 'fire-eq-tech-moex-108-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依防火牆及防火水幕設置基準規定，若防火水幕之防護高度為12公尺，請問其每公尺水幕長度 放水量應在每分鐘多少公升以上？', '["90", "100", "110", "120"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "e27db18de2d3", "answer_pdf_sha1": "28ae3d146415", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00836', 'fire-eq-tech', 'fire-eq-tech-moex-108-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '下列有關二氧化碳滅火設備各種標示規格規定之敘述，何者錯誤？', '["手動啟動裝置標示規格，尺寸A：300 mm以上，紅底白字", "手動啟動裝置標示規格，尺寸B：80 mm以上，紅底白字", "放射表示燈規格，尺寸A：280 mm以上，點燈時白底紅字", "放射表示燈規格，尺寸B：80 mm以上，燈具本體為紅色"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "e27db18de2d3", "answer_pdf_sha1": "28ae3d146415", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00837', 'fire-eq-tech', 'fire-eq-tech-moex-108-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依可燃性高壓氣體儲存場所防爆牆設置基準規定，防爆牆分為鋼筋混凝土製、混凝土空心磚製及 鋼板製等三種，並應設置於堅固基礎上，其強度應能承受可能預料之氣體爆炸衝擊。下列有關其 構造規定何者錯誤？', '["鋼筋混凝土製防爆牆，其厚度應在150 mm以上，高度應在2000 mm以上", "混凝土空心磚製防爆牆，其厚度應在200 mm以上，高度應在2000 mm以上，3000 mm以下", "鋼板製防爆牆，其厚度應在6.0 mm以上，高度應在2000 mm以上", "防爆牆之端部或隙角部分須用直徑10 mm以上鋼筋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "e27db18de2d3", "answer_pdf_sha1": "28ae3d146415", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00838', 'fire-eq-tech', 'fire-eq-tech-moex-108-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依各類場所消防安全設備設置標準，下列有關室內消防栓箱的規定何者錯誤？', '["箱身為厚度在1.6毫米以上之鋼板或具同等性能以上之不燃材料者", "具有足夠裝設消防栓、水帶及瞄子等裝備之深度", "箱面表面積在0.7平方公尺以上", "箱面有明顯而不易脫落之消防栓字樣，每字在2平方公分以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "e27db18de2d3", "answer_pdf_sha1": "28ae3d146415", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00839', 'fire-eq-tech', 'fire-eq-tech-moex-108-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，下列何種處所得免設排煙設備？', '["建築物在第十層以下之各樓層（地下層除外），其非居室部分，天花板及室內牆面，以耐燃一 級材料裝修，且除面向室外之開口外，以半小時以上防火時效之防火門窗等防火設備區劃者", "建築物在第十層以下之各樓層（地下層除外），其非居室部分，樓地板面積每200平方公尺以 下，以防煙壁區劃者", "建築物在第十層以下之各樓層（地下層除外），其居室部分，樓地板面積在200平方公尺以下， 天花板及室內牆面，且包括其底材，均以耐燃一級材料裝修者", "設有室內消防栓等滅火設備之場所"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "e27db18de2d3", "answer_pdf_sha1": "28ae3d146415", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00840', 'fire-eq-tech', 'fire-eq-tech-moex-108-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依消防機關辦理建築物消防安全設備審查及查驗作業基準規定，消防安全設備圖說審查及竣工查 驗之期限，以受理案件後Ｘ至Ｙ日內結案為原則。但供公眾使用建築物或構造複雜者，得視需要 延長，並通知申請人，最長不得超過Ｚ日，請問下列何者正確？', '["X=5，Y=10，Z=20", "X=7，Y=15，Z=20", "X=7，Y=10，Z=30", "X=7，Y=10，Z=20"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "e27db18de2d3", "answer_pdf_sha1": "28ae3d146415", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00841', 'fire-eq-tech', 'fire-eq-tech-moex-108-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依各類場所消防安全設備檢修及申報作業基準規定，有關避難器具開口部大小之檢查，下列何者 正確？', '["救助袋之開口部大小，高50 cm以上，寬60 cm以上", "緩降機之開口部大小，高80 cm以上，寬50 cm以上或高100 cm以上，寬45 cm以上", "滑台之開口部大小，高60 cm以上，寬為滑台最大寬度以上", "避難橋之開口部大小，高160 cm以上，寬為避難橋最大寬度以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "e27db18de2d3", "answer_pdf_sha1": "28ae3d146415", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00842', 'fire-eq-tech', 'fire-eq-tech-moex-108-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依各類場所消防安全設備檢修及申報作業基準規定，有關配線絕緣阻抗試驗合格之判定，若電壓 超過300 V者，其絕緣電阻值至少應為多少以上？', '["0.1 MΩ", "0.2 MΩ", "0.4 MΩ", "3 MΩ"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "e27db18de2d3", "answer_pdf_sha1": "28ae3d146415", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00843', 'fire-eq-tech', 'fire-eq-tech-moex-108-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依消防法施行細則，有關消防安全設備之設計、監造、裝置及檢修工作項目之規定，下列何者正確？', '["檢修：指依消防法規定，受託檢查各類場所之消防安全設備，並製作消防安全設備檢修報告書", "裝置：指消防安全設備種類及數量之規劃，並製作消防安全設備圖說", "監造：指消防安全設備施工完成後之功能測試，並製作消防安全設備測試報告書", "設計：指消防安全設備施工中須經試驗或勘驗事項之查核，並製作紀錄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "e27db18de2d3", "answer_pdf_sha1": "28ae3d146415", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
